content.content:
  1→// Package main implements the Aileron MCP gateway.
  2→//
  3→// The gateway aggregates tools from downstream MCP servers, re-exposes them
  4→// under namespaced names, and intercepts every tools/call for policy evaluation.
  5→// When a call requires approval, the original request is queued and auto-executed
  6→// once a human approves it through the Aileron UI.
  7→
  8→package main
  9→
 10→import (
 11→	"context"
 12→	"fmt"
 13→	"log/slog"
 14→	"strings"
 15→	"time"
 16→
 17→	"github.com/ALRubinger/aileron/core/approval"
 18→	"github.com/ALRubinger/aileron/core/audit"
 19→	"github.com/ALRubinger/aileron/core/config"
 20→	"github.com/ALRubinger/aileron/core/mcpclient"
 21→	"github.com/ALRubinger/aileron/core/model"
 22→	"github.com/ALRubinger/aileron/core/policy"
 23→	"github.com/ALRubinger/aileron/core/vault"
 24→	"github.com/google/uuid"
 25→)
 26→
 27→const (
 28→	// namespaceSep separates the server name from the tool name in
 29→	// the aggregated tool list (e.g. "github__create_pull_request").
 30→	namespaceSep = "__"
 31→
 32→	// checkApprovalTool is the meta-tool for checking approval status.
 33→	checkApprovalTool = "aileron__check_approval"
 34→)
 35→
 36→// toolRoute maps a namespaced tool name back to its downstream client and
 37→// the original (un-prefixed) tool name.
 38→type toolRoute struct {
 39→	client       *mcpclient.Client
 40→	originalName string
 41→	serverName   string
 42→	// toolPrefix from the server's policy_mapping config, if any.
 43→	toolPrefix string
 44→}
 45→
 46→// gateway manages downstream MCP server connections, policy evaluation,
 47→// approval orchestration, and tool routing.
 48→type gateway struct {
 49→	clients      []*mcpclient.Client
 50→	routes       map[string]toolRoute // namespaced tool name → route
 51→	tools        []toolDef            // aggregated tool list (cached)
 52→	policyEngine policy.Engine
 53→	approvals    approval.Orchestrator
 54→	auditStore   audit.Store
 55→	queue        *callQueue
 56→	workspaceID  string
 57→	log          *slog.Logger
 58→}
 59→
 60→// gatewayConfig holds the dependencies for creating a new gateway.
 61→type gatewayConfig struct {
 62→	Cfg          *config.Config
 63→	Vault        vault.Vault
 64→	PolicyEngine policy.Engine
 65→	Approvals    approval.Orchestrator
 66→	AuditStore   audit.Store
 67→	Log          *slog.Logger
 68→}
 69→
 70→// newGateway connects to all downstream MCP servers defined in cfg, discovers
 71→// their tools, and builds the aggregated tool routing table.
 72→func newGateway(ctx context.Context, gc gatewayConfig) (*gateway, error) {
 73→	workspaceID := gc.Cfg.WorkspaceID
 74→	if workspaceID == "" {
 75→		workspaceID = "default"
 76→	}
 77→
 78→	g := &gateway{
 79→		routes:       make(map[string]toolRoute),
 80→		policyEngine: gc.PolicyEngine,
 81→		approvals:    gc.Approvals,
 82→		auditStore:   gc.AuditStore,
 83→		queue:        newCallQueue(),
 84→		workspaceID:  workspaceID,
 85→		log:          gc.Log,
 86→	}
 87→
 88→	for _, ds := range gc.Cfg.DownstreamServers {
 89→		// Resolve vault:// env vars.
 90→		env, err := resolveEnv(ctx, ds.Env, gc.Vault)
 91→		if err != nil {
 92→			return nil, fmt.Errorf("gateway: server %q: %w", ds.Name, err)
 93→		}
 94→
 95→		// Convert map to KEY=VALUE slice for subprocess.
 96→		envSlice := make([]string, 0, len(env))
 97→		for k, val := range env {
 98→			envSlice = append(envSlice, k+"="+val)
 99→		}
100→
101→		client, err := mcpclient.NewClient(ctx, ds.Name, ds.Command, envSlice)
102→		if err != nil {
103→			g.closeAll()
104→			return nil, fmt.Errorf("gateway: start server %q: %w", ds.Name, err)
105→		}
106→
107→		g.clients = append(g.clients, client)
108→
109→		// Determine tool prefix for policy mapping.
110→		var toolPrefix string
111→		if ds.PolicyMapping != nil {
112→			toolPrefix = ds.PolicyMapping.ToolPrefix
113→		}
114→
115→		// Register each tool with a namespaced name.
116→		for _, tool := range client.Tools() {
117→			qualifiedName := ds.Name + namespaceSep + tool.Name
118→			g.routes[qualifiedName] = toolRoute{
119→				client:       client,
120→				originalName: tool.Name,
121→				serverName:   ds.Name,
122→				toolPrefix:   toolPrefix,
123→			}
124→			g.tools = append(g.tools, toolDef{
125→				Name:        qualifiedName,
126→				Description: fmt.Sprintf("%s (via %s)", tool.Description, ds.Name),
127→				InputSchema: toSchema(tool.InputSchema),
128→			})
129→		}
130→
131→		gc.Log.Info("connected downstream server",
132→			"name", ds.Name,
133→			"tools", len(client.Tools()),
134→		)
135→	}
136→
137→	// Always add the check_approval meta-tool.
138→	g.tools = append(g.tools, checkApprovalToolDef())
139→
140→	return g, nil
141→}
142→
143→// aggregatedTools returns the full list of tools from all downstream servers
144→// plus the aileron meta-tools.
145→func (g *gateway) aggregatedTools() []toolDef {
146→	return g.tools
147→}
148→
149→// routeToolCall intercepts a tool call, evaluates it against policy, and
150→// either forwards it to the downstream server, blocks it for approval, or
151→// denies it.
152→func (g *gateway) routeToolCall(ctx context.Context, name string, arguments map[string]any) toolResult {
153→	if name == checkApprovalTool {
154→		return g.handleCheckApproval(ctx, arguments)
155→	}
156→
157→	route, ok := g.routes[name]
158→	if !ok {
159→		return toolResult{
160→			Content: []toolContent{{Type: "text", Text: "Unknown tool: " + name}},
161→			IsError: true,
162→		}
163→	}
164→
165→	// Emit intercepted audit event.
166→	g.emitAuditEvent(ctx, model.EventTypeToolCallIntercepted, map[string]any{
167→		"tool":        name,
168→		"server_name": route.serverName,
169→		"original":    route.originalName,
170→	})
171→
172→	// Build the policy evaluation request.
173→	actionType := route.originalName
174→	if route.toolPrefix != "" {
175→		actionType = route.toolPrefix + "." + route.originalName
176→	}
177→
178→	evalReq := policy.EvaluationRequest{
179→		WorkspaceID: g.workspaceID,
180→		AgentID:     "mcp_agent",
181→		Action: model.ActionIntent{
182→			Type:    actionType,
183→			Summary: fmt.Sprintf("Tool call: %s", name),
184→		},
185→		Context: model.IntentContext{
186→			SourcePlatform: "aileron_gateway",
187→		},
188→		ToolCall: &policy.ToolCallContext{
189→			ServerName:    route.serverName,
190→			ToolName:      route.originalName,
191→			QualifiedName: name,
192→			Arguments:     arguments,
193→		},
194→	}
195→
196→	// Evaluate policy.
197→	decision, err := g.policyEngine.Evaluate(ctx, evalReq)
198→	if err != nil {
199→		g.log.Error("policy evaluation failed", "tool", name, "error", err)
200→		// On policy error, deny by default for safety.
201→		g.emitAuditEvent(ctx, model.EventTypeToolCallDenied, map[string]any{
202→			"tool":   name,
203→			"reason": fmt.Sprintf("policy evaluation error: %v", err),
204→		})
205→		return toolResult{
206→			Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Policy evaluation failed: %v", err)}},
207→			IsError: true,
208→		}
209→	}
210→
211→	switch decision.Disposition {
212→	case model.DispositionAllow, model.DispositionAllowModified:
213→		g.emitAuditEvent(ctx, model.EventTypeToolCallForwarded, map[string]any{
214→			"tool":        name,
215→			"disposition": string(decision.Disposition),
216→		})
217→		return g.forwardToDownstream(ctx, route, arguments)
218→
219→	case model.DispositionDeny:
220→		reason := decision.DenialReason
221→		if reason == "" {
222→			reason = "denied by policy"
223→		}
224→		g.emitAuditEvent(ctx, model.EventTypeToolCallDenied, map[string]any{
225→			"tool":   name,
226→			"reason": reason,
227→		})
228→		return toolResult{
229→			Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Action denied: %s", reason)}},
230→			IsError: true,
231→		}
232→
233→	case model.DispositionRequireApproval:
234→		g.emitAuditEvent(ctx, model.EventTypeToolCallPendingApproval, map[string]any{
235→			"tool": name,
236→		})
237→		return g.holdForApproval(ctx, name, route, arguments, decision)
238→
239→	default:
240→		g.emitAuditEvent(ctx, model.EventTypeToolCallForwarded, map[string]any{
241→			"tool":        name,
242→			"disposition": string(decision.Disposition),
243→		})
244→		return g.forwardToDownstream(ctx, route, arguments)
245→	}
246→}
247→
248→// emitAuditEvent records an audit event if the audit store is configured.
249→func (g *gateway) emitAuditEvent(ctx context.Context, eventType model.EventType, payload map[string]any) {
250→	if g.auditStore == nil {
251→		return
252→	}
253→	event := audit.Event{
254→		EventID:   uuid.New().String(),
255→		EventType: eventType,
256→		Actor: model.ActorRef{
257→			ID:   "aileron_gateway",
258→			Type: model.ActorTypeService,
259→		},
260→		Payload:   payload,
261→		Timestamp: time.Now(),
262→	}
263→	if err := g.auditStore.Append(ctx, event); err != nil {
264→		g.log.Warn("failed to record audit event",
265→			"event_type", string(eventType),
266→			"error", err,
267→		)
268→	}
269→}
270→
271→// forwardToDownstream sends a tool call to the downstream MCP server and
272→// returns its result.
273→func (g *gateway) forwardToDownstream(ctx context.Context, route toolRoute, arguments map[string]any) toolResult {
274→	if route.client == nil {
275→		return toolResult{
276→			Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Downstream server not available for tool: %s", route.originalName)}},
277→			IsError: true,
278→		}
279→	}
280→	result, err := route.client.CallTool(ctx, route.originalName, arguments)
281→	if err != nil {
282→		return toolResult{
283→			Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Error calling %s: %v", route.originalName, err)}},
284→			IsError: true,
285→		}
286→	}
287→
288→	var content []toolContent
289→	for _, c := range result.Content {
290→		content = append(content, toolContent{Type: c.Type, Text: c.Text})
291→	}
292→	return toolResult{
293→		Content: content,
294→		IsError: result.IsError,
295→	}
296→}
297→
298→// holdForApproval queues a tool call for later execution and returns a
299→// pending-approval response to the agent.
300→func (g *gateway) holdForApproval(ctx context.Context, qualifiedName string, route toolRoute, arguments map[string]any, decision model.Decision) toolResult {
301→	// Create an approval request if orchestrator is available.
302→	approvalID := ""
303→	if g.approvals != nil {
304→		rationale := "Policy requires approval"
305→		if len(decision.MatchedPolicies) > 0 {
306→			rationale = decision.MatchedPolicies[0].Explanation
307→		}
308→
309→		appr, err := g.approvals.Request(ctx, approval.ApprovalRequest{
310→			IntentID:    fmt.Sprintf("tool-call-%s-%d", qualifiedName, g.queue.len()),
311→			WorkspaceID: g.workspaceID,
312→			Rationale:   rationale,
313→		})
314→		if err != nil {
315→			g.log.Error("failed to create approval request", "tool", qualifiedName, "error", err)
316→			return toolResult{
317→				Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Failed to create approval: %v", err)}},
318→				IsError: true,
319→			}
320→		}
321→		approvalID = appr.ApprovalID
322→	} else {
323→		// No orchestrator — generate a placeholder ID.
324→		approvalID = fmt.Sprintf("apr_pending_%d", g.queue.len())
325→	}
326→
327→	// Queue the original call for auto-execution after approval.
328→	g.queue.enqueue(approvalID, queuedCall{
329→		ServerName:    route.serverName,
330→		ToolName:      route.originalName,
331→		QualifiedName: qualifiedName,
332→		Arguments:     arguments,
333→	})
334→
335→	g.log.Info("tool call held for approval",
336→		"tool", qualifiedName,
337→		"approval_id", approvalID,
338→	)
339→
340→	return jsonResult(map[string]any{
341→		"status":      "pending_approval",
342→		"approval_id": approvalID,
343→		"message":     fmt.Sprintf("This action requires human approval. Use %s with the approval_id to check status.", checkApprovalTool),
344→		"tool":        qualifiedName,
345→	})
346→}
347→
348→// handleCheckApproval checks an approval's status and, if approved,
349→// auto-executes the queued tool call.
350→func (g *gateway) handleCheckApproval(ctx context.Context, args map[string]any) toolResult {
351→	approvalID := argStr(args, "approval_id")
352→	if approvalID == "" {
353→		return errorResult("approval_id is required")
354→	}
355→
356→	// Check if we have a queued call for this approval.
357→	call, queued := g.queue.peek(approvalID)
358→	if !queued {
359→		return jsonResult(map[string]any{
360→			"approval_id": approvalID,
361→			"status":      "not_found",
362→			"message":     "No pending tool call found for this approval ID.",
363→		})
364→	}
365→
366→	// Check the approval status via the orchestrator.
367→	if g.approvals != nil {
368→		appr, err := g.approvals.Get(ctx, approvalID)
369→		if err != nil {
370→			return jsonResult(map[string]any{
371→				"approval_id": approvalID,
372→				"status":      "error",
373→				"message":     fmt.Sprintf("Failed to check approval: %v", err),
374→			})
375→		}
376→
377→		switch appr.Status {
378→		case approval.StatusPending:
379→			return jsonResult(map[string]any{
380→				"approval_id": approvalID,
381→				"status":      "pending",
382→				"message":     "Still waiting for human approval.",
383→				"tool":        call.QualifiedName,
384→			})
385→
386→		case approval.StatusDenied:
387→			g.queue.dequeue(approvalID)
388→			return toolResult{
389→				Content: []toolContent{{Type: "text", Text: fmt.Sprintf("Action denied: %s → %s", call.summary(), approvalID)}},
390→				IsError: true,
391→			}
392→
393→		case approval.StatusApproved, approval.StatusModified:
394→			// Approved — auto-execute the queued call.
395→			return g.executeQueuedCall(ctx, approvalID)
396→
397→		default:
398→			return jsonResult(map[string]any{
399→				"approval_id": approvalID,
400→				"status":      string(appr.Status),
401→				"message":     fmt.Sprintf("Approval status: %s", appr.Status),
402→			})
403→		}
404→	}
405→
406→	// No orchestrator — the call stays queued until manually managed.
407→	return jsonResult(map[string]any{
408→		"approval_id": approvalID,
409→		"status":      "pending",
410→		"message":     "Waiting for approval. No approval orchestrator configured.",
411→		"tool":        call.QualifiedName,
412→	})
413→}
414→
415→// executeQueuedCall dequeues and forwards a previously held tool call.
416→func (g *gateway) executeQueuedCall(ctx context.Context, approvalID string) toolResult {
417→	call, ok := g.queue.dequeue(approvalID)
418→	if !ok {
419→		return errorResult("queued call not found for approval: " + approvalID)
420→	}
421→
422→	route, ok := g.routes[call.QualifiedName]
423→	if !ok {
424→		return errorResult("downstream server no longer available for tool: " + call.QualifiedName)
425→	}
426→
427→	g.log.Info("auto-executing approved tool call",
428→		"tool", call.QualifiedName,
429→		"approval_id", approvalID,
430→	)
431→
432→	return g.forwardToDownstream(ctx, route, call.Arguments)
433→}
434→
435→// closeAll terminates all downstream client connections and logs each shutdown.
436→func (g *gateway) closeAll() {
437→	for _, c := range g.clients {
438→		g.log.Info("closing downstream server", "name", c.Name())
439→		if err := c.Close(); err != nil {
440→			g.log.Warn("error closing downstream server",
441→				"name", c.Name(),
442→				"error", err,
443→			)
444→		}
445→	}
446→}
447→
448→// Shutdown gracefully shuts down the gateway, closing all downstream
449→// connections. The provided context can be used to set a deadline.
450→func (g *gateway) Shutdown(ctx context.Context) {
451→	g.log.Info("gateway shutdown starting")
452→
453→	done := make(chan struct{})
454→	go func() {
455→		g.closeAll()
456→		close(done)
457→	}()
458→
459→	select {
460→	case <-done:
461→		g.log.Info("gateway shutdown complete")
462→	case <-ctx.Done():
463→		g.log.Warn("gateway shutdown timed out", "error", ctx.Err())
464→	}
465→}
466→
467→// resolveEnv resolves vault:// prefixed env values using the vault, or
468→// passes them through unchanged. If vault is nil, vault:// references are
469→// treated as an error.
470→func resolveEnv(ctx context.Context, env map[string]string, v vault.Vault) (map[string]string, error) {
471→	if len(env) == 0 {
472→		return nil, nil
473→	}
474→
475→	vaultGet := func(path string) ([]byte, error) {
476→		if v == nil {
477→			return nil, fmt.Errorf("vault not available; cannot resolve vault://%s", path)
478→		}
479→		secret, err := v.Get(ctx, path)
480→		if err != nil {
481→			return nil, err
482→		}
483→		return secret.Value, nil
484→	}
485→
486→	return config.ResolveVaultEnv(env, vaultGet)
487→}
