20→func (v *MemVault) Get(_ context.Context, path string) (Secret, error) {
21→	v.mu.RLock()
22→	defer v.mu.RUnlock()
23→	s, ok := v.secrets[path]
24→	if !ok {
25→		return Secret{}, &errNotFound{path: path}
26→	}
27→	return s, nil
28→}
29→
