489→// checkApprovalToolDef returns the tool definition for the aileron meta-tool.
490→func checkApprovalToolDef() toolDef {
491→	return toolDef{
492→		Name:        checkApprovalTool,
493→		Description: "Check the status of a pending approval. If the action has been approved, the original tool call is automatically executed and its result is returned.",
494→		InputSchema: schema{
495→			Type: "object",
496→			Properties: map[string]schemaProp{
497→				"approval_id": {Type: "string", Description: "The approval ID returned when a tool call was held for approval"},
498→			},
499→			Required: []string{"approval_id"},
500→		},
501→	}
502→}
503→
504→// toSchema converts a generic map (from MCP tools/list) to our schema type.
505→func toSchema(raw map[string]any) schema {
506→	if raw == nil {
507→		return schema{Type: "object"}
508→	}
509→
510→	s := schema{Type: "object"}
511→
512→	if t, ok := raw["type"].(string); ok {
513→		s.Type = t
514→	}
515→
516→	if props, ok := raw["properties"].(map[string]any); ok {
517→		s.Properties = make(map[string]schemaProp, len(props))
518→		for name, v := range props {
519→			prop := schemaProp{}
520→			if pm, ok := v.(map[string]any); ok {
521→				if t, ok := pm["type"].(string); ok {
522→					prop.Type = t
523→				}
524→				if d, ok := pm["description"].(string); ok {
525→					prop.Description = d
526→				}
527→			}
528→			s.Properties[name] = prop
529→		}
530→	}
531→
532→	if req, ok := raw["required"].([]any); ok {
533→		for _, r := range req {
534→			if rs, ok := r.(string); ok {
535→				s.Required = append(s.Required, rs)
536→			}
537→		}
538→	}
539→
540→	return s
541→}
