  1→// Package mcpclient provides a Go client that speaks Model Context Protocol (MCP)
  2→// over stdio to downstream MCP servers running as subprocesses.
  3→//
  4→// Communication uses newline-delimited JSON-RPC 2.0 over the subprocess's
  5→// stdin (requests) and stdout (responses).
  6→package mcpclient
  7→
  8→import (
  9→	"bufio"
 10→	"context"
 11→	"encoding/json"
 12→	"fmt"
 13→	"io"
 14→	"os"
 15→	"os/exec"
 16→	"sync"
 17→	"sync/atomic"
 18→	"syscall"
 19→	"time"
 20→)
 21→
 22→// ToolDef describes a tool exposed by a downstream MCP server.
 23→type ToolDef struct {
 24→	Name        string         `json:"name"`
 25→	Description string         `json:"description"`
 26→	InputSchema map[string]any `json:"inputSchema"`
 27→}
 28→
 29→// ToolResult is the result from a tools/call invocation.
 30→type ToolResult struct {
 31→	Content []ToolContent `json:"content"`
 32→	IsError bool          `json:"isError,omitempty"`
 33→}
 34→
 35→// ToolContent represents a single content block within a tool result.
 36→type ToolContent struct {
 37→	Type string `json:"type"`
 38→	Text string `json:"text"`
 39→}
 40→
 41→// Client manages a connection to a single downstream MCP server subprocess.
 42→type Client struct {
 43→	name   string
 44→	cmd    *exec.Cmd
 45→	stdin  io.WriteCloser
 46→	stdout *bufio.Reader
 47→	mu     sync.Mutex // protects writes to stdin and reads from stdout
 48→	tools  []ToolDef
 49→	nextID int64
 50→}
 51→
 52→// JSON-RPC 2.0 wire types (internal).
 53→
 54→type jsonrpcRequest struct {
 55→	JSONRPC string `json:"jsonrpc"`
 56→	ID      any    `json:"id,omitempty"`
 57→	Method  string `json:"method"`
 58→	Params  any    `json:"params,omitempty"`
 59→}
 60→
 61→type jsonrpcResponse struct {
 62→	JSONRPC string          `json:"jsonrpc"`
 63→	ID      json.RawMessage `json:"id,omitempty"`
 64→	Result  json.RawMessage `json:"result,omitempty"`
 65→	Error   *jsonrpcError   `json:"error,omitempty"`
 66→}
 67→
 68→type jsonrpcError struct {
 69→	Code    int    `json:"code"`
 70→	Message string `json:"message"`
 71→}
 72→
 73→func (e *jsonrpcError) Error() string {
 74→	return fmt.Sprintf("jsonrpc error %d: %s", e.Code, e.Message)
 75→}
 76→
 77→// NewClient spawns a downstream MCP server as a subprocess and performs the
 78→// MCP initialize handshake. The command slice must contain at least the
 79→// program name; additional elements are passed as arguments. The env slice
 80→// is merged with os.Environ() so the subprocess inherits the current
 81→// environment plus any overrides.
 82→func NewClient(ctx context.Context, name string, command []string, env []string) (*Client, error) {
 83→	if len(command) == 0 {
 84→		return nil, fmt.Errorf("mcpclient: command must not be empty")
 85→	}
 86→
 87→	cmd := exec.CommandContext(ctx, command[0], command[1:]...)
 88→	cmd.Env = append(os.Environ(), env...)
 89→	cmd.Stderr = os.Stderr
 90→
 91→	stdinPipe, err := cmd.StdinPipe()
 92→	if err != nil {
 93→		return nil, fmt.Errorf("mcpclient: stdin pipe: %w", err)
 94→	}
 95→
 96→	stdoutPipe, err := cmd.StdoutPipe()
 97→	if err != nil {
 98→		return nil, fmt.Errorf("mcpclient: stdout pipe: %w", err)
 99→	}
100→
101→	if err := cmd.Start(); err != nil {
102→		return nil, fmt.Errorf("mcpclient: start %q: %w", command[0], err)
103→	}
104→
105→	c := &Client{
106→		name:   name,
107→		cmd:    cmd,
108→		stdin:  stdinPipe,
109→		stdout: bufio.NewReader(stdoutPipe),
110→		nextID: 1, // 1 is reserved for the initialize request
111→	}
112→
113→	// --- MCP initialize handshake ---
114→
115→	initParams := map[string]any{
116→		"protocolVersion": "2024-11-05",
117→		"capabilities":    map[string]any{},
118→		"clientInfo": map[string]any{
119→			"name":    "aileron-gateway",
120→			"version": "0.0.1",
121→		},
122→	}
123→
124→	_, err = c.sendRequest("initialize", initParams)
125→	if err != nil {
126→		// Best-effort cleanup on failure.
127→		_ = c.Close()
128→		return nil, fmt.Errorf("mcpclient: initialize handshake: %w", err)
129→	}
130→
131→	// Send the initialized notification (no ID — it's a notification).
132→	if err := c.sendNotification("notifications/initialized"); err != nil {
133→		_ = c.Close()
134→		return nil, fmt.Errorf("mcpclient: initialized notification: %w", err)
135→	}
136→
137→	// Discover available tools.
138→	if _, err := c.DiscoverTools(ctx); err != nil {
139→		_ = c.Close()
140→		return nil, fmt.Errorf("mcpclient: discover tools: %w", err)
141→	}
142→
143→	return c, nil
144→}
145→
146→// DiscoverTools sends a tools/list request and caches the result.
147→func (c *Client) DiscoverTools(_ context.Context) ([]ToolDef, error) {
148→	raw, err := c.sendRequest("tools/list", nil)
149→	if err != nil {
150→		return nil, err
151→	}
152→
153→	var envelope struct {
154→		Tools []ToolDef `json:"tools"`
155→	}
156→	if err := json.Unmarshal(raw, &envelope); err != nil {
157→		return nil, fmt.Errorf("mcpclient: parse tools/list result: %w", err)
158→	}
159→
160→	c.tools = envelope.Tools
161→	return c.tools, nil
162→}
163→
164→// CallTool invokes a tool on the downstream MCP server by name.
165→func (c *Client) CallTool(_ context.Context, name string, arguments map[string]any) (*ToolResult, error) {
166→	params := map[string]any{
167→		"name":      name,
168→		"arguments": arguments,
169→	}
170→
171→	raw, err := c.sendRequest("tools/call", params)
172→	if err != nil {
173→		return nil, err
174→	}
175→
176→	var result ToolResult
177→	if err := json.Unmarshal(raw, &result); err != nil {
178→		return nil, fmt.Errorf("mcpclient: parse tools/call result: %w", err)
179→	}
180→
181→	return &result, nil
182→}
183→
184→// Tools returns the cached list of tools discovered from the server.
185→func (c *Client) Tools() []ToolDef {
186→	return c.tools
187→}
188→
189→// Name returns the human-readable name of this client connection.
190→func (c *Client) Name() string {
191→	return c.name
192→}
193→
194→// Close terminates the subprocess. It sends SIGTERM first, then SIGKILL
195→// after a 5-second timeout if the process hasn't exited.
196→func (c *Client) Close() error {
197→	if c.cmd == nil || c.cmd.Process == nil {
198→		return nil
199→	}
200→
201→	// Close stdin so the subprocess sees EOF.
202→	_ = c.stdin.Close()
203→
204→	// Send SIGTERM.
205→	if err := c.cmd.Process.Signal(syscall.SIGTERM); err != nil {
206→		// Process may have already exited; just wait.
207→		_ = c.cmd.Wait()
208→		return nil
209→	}
210→
211→	// Wait up to 5 seconds for graceful exit.
212→	done := make(chan error, 1)
213→	go func() {
214→		done <- c.cmd.Wait()
215→	}()
216→
217→	select {
218→	case err := <-done:
219→		return err
220→	case <-time.After(5 * time.Second):
221→		_ = c.cmd.Process.Kill()
222→		return <-done
223→	}
224→}
225→
226→// nextRequestID returns a monotonically increasing request ID.
227→func (c *Client) nextRequestID() int64 {
228→	return atomic.AddInt64(&c.nextID, 1)
229→}
230→
231→// sendRequest sends a JSON-RPC request and waits for the corresponding
232→// response. It returns the raw "result" field on success.
233→func (c *Client) sendRequest(method string, params any) (json.RawMessage, error) {
234→	c.mu.Lock()
235→	defer c.mu.Unlock()
236→
237→	id := c.nextRequestID()
238→	req := jsonrpcRequest{
239→		JSONRPC: "2.0",
240→		ID:      id,
241→		Method:  method,
242→		Params:  params,
243→	}
244→
245→	data, err := json.Marshal(req)
246→	if err != nil {
247→		return nil, fmt.Errorf("mcpclient: marshal request: %w", err)
248→	}
249→
250→	// Write newline-delimited JSON.
251→	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
252→		return nil, fmt.Errorf("mcpclient: write request: %w", err)
253→	}
254→
255→	resp, err := c.readResponse()
256→	if err != nil {
257→		return nil, err
258→	}
259→
260→	if resp.Error != nil {
261→		return nil, resp.Error
262→	}
263→
264→	return resp.Result, nil
265→}
266→
267→// sendNotification sends a JSON-RPC notification (no ID, no response expected).
268→func (c *Client) sendNotification(method string) error {
269→	c.mu.Lock()
270→	defer c.mu.Unlock()
271→
272→	req := jsonrpcRequest{
273→		JSONRPC: "2.0",
274→		Method:  method,
275→	}
276→
277→	data, err := json.Marshal(req)
278→	if err != nil {
279→		return fmt.Errorf("mcpclient: marshal notification: %w", err)
280→	}
281→
282→	if _, err := fmt.Fprintf(c.stdin, "%s\n", data); err != nil {
283→		return fmt.Errorf("mcpclient: write notification: %w", err)
284→	}
285→
286→	return nil
287→}
288→
289→// readResponse reads one newline-delimited JSON line from the subprocess
290→// stdout and parses it as a JSON-RPC response.
291→func (c *Client) readResponse() (*jsonrpcResponse, error) {
292→	line, err := c.stdout.ReadBytes('\n')
293→	if err != nil {
294→		return nil, fmt.Errorf("mcpclient: read response: %w", err)
295→	}
296→
297→	var resp jsonrpcResponse
298→	if err := json.Unmarshal(line, &resp); err != nil {
299→		return nil, fmt.Errorf("mcpclient: parse response: %w (raw: %s)", err, string(line))
300→	}
301→
302→	return &resp, nil
303→}
