 65→func TestRouteToolCall_PolicyAllow(t *testing.T) {
 66→	// Use a capturing engine to verify the allow path is taken and
 67→	// audit events are emitted. We can't forward to a nil client,
 68→	// so we verify via audit events that the "forwarded" event fires.
 69→	var captured policy.EvaluationRequest
 70→	pe := &capturingPolicyEngine{
 71→		decision: model.Decision{
 72→			Disposition: model.DispositionAllow,
 73→			RiskLevel:   model.RiskLevelLow,
 74→		},
 75→		captured: &captured,
 76→	}
 77→	gw := testGateway(t, pe)
 78→	addFakeRoute(gw, "fs__read_file", "fs", "read_file", "filesystem")
 79→	store := gw.auditStore.(*memAuditStore)
 80→
 81→	ctx := context.Background()
 82→	_ = gw.routeToolCall(ctx, "fs__read_file", map[string]any{"path": "/tmp/test"})
 83→
 84→	// Verify policy was evaluated.
 85→	if captured.Action.Type != "filesystem.read_file" {
 86→		t.Errorf("Action.Type = %q, want %q", captured.Action.Type, "filesystem.read_file")
 87→	}
 88→
 89→	// Verify audit events: intercepted + forwarded.
 90→	store.mu.RLock()
 91→	defer store.mu.RUnlock()
 92→	if len(store.events) < 2 {
 93→		t.Fatalf("expected at least 2 audit events, got %d", len(store.events))
 94→	}
 95→	if store.events[0].EventType != model.EventTypeToolCallIntercepted {
 96→		t.Errorf("event[0] = %q, want intercepted", store.events[0].EventType)
 97→	}
 98→	if store.events[1].EventType != model.EventTypeToolCallForwarded {
 99→		t.Errorf("event[1] = %q, want forwarded", store.events[1].EventType)
100→	}
101→}
