279→	}
280→
281→	// The subprocess should be running.
282→	if client.cmd.Process == nil {
283→		t.Fatal("expected subprocess to be running")
284→	}
285→
286→	pid := client.cmd.Process.Pid
287→
288→	// Close may return a "signal: terminated" error from Wait, which is
289→	// expected when we SIGTERM the subprocess. That's not a failure.
290→	_ = client.Close()
291→
292→	// Give the OS a moment to clean up the process.
293→	time.Sleep(50 * time.Millisecond)
294→
295→	// Verify the process is no longer running. Sending signal 0 checks
296→	// existence without actually signaling.
297→	proc, err := os.FindProcess(pid)
298→	if err != nil {
299→		// Process not found — good.
300→		return
301→	}
302→	// On Unix, FindProcess always succeeds; use Signal(0) to probe.
303→	if err := proc.Signal(syscall.Signal(0)); err == nil {
304→		t.Error("expected subprocess to be terminated, but it's still running")
305→	}
306→}
