 1→package mem
 2→
 3→import (
 4→	"context"
 5→	"sync"
 6→
 7→	api "github.com/ALRubinger/aileron/core/api/gen"
 8→	"github.com/ALRubinger/aileron/core/store"
 9→)
10→
11→// ApprovalStore is a thread-safe in-memory implementation of store.ApprovalStore.
12→type ApprovalStore struct {
13→	mu        sync.RWMutex
14→	approvals map[string]api.Approval
15→}
16→
17→// NewApprovalStore returns an empty in-memory approval store.
18→func NewApprovalStore() *ApprovalStore {
19→	return &ApprovalStore{approvals: make(map[string]api.Approval)}
20→}
21→
22→func (s *ApprovalStore) Create(_ context.Context, approval api.Approval) error {
23→	s.mu.Lock()
24→	defer s.mu.Unlock()
25→	s.approvals[approval.ApprovalId] = approval
26→	return nil
27→}
28→
29→func (s *ApprovalStore) Get(_ context.Context, approvalID string) (api.Approval, error) {
30→	s.mu.RLock()
31→	defer s.mu.RUnlock()
32→	a, ok := s.approvals[approvalID]
33→	if !ok {
34→		return api.Approval{}, &store.ErrNotFound{Entity: "approval", ID: approvalID}
35→	}
36→	return a, nil
37→}
38→
39→func (s *ApprovalStore) List(_ context.Context, filter store.ApprovalFilter) ([]api.Approval, error) {
40→	s.mu.RLock()
41→	defer s.mu.RUnlock()
42→	var result []api.Approval
43→	for _, a := range s.approvals {
44→		if filter.WorkspaceID != "" {
45→			if a.WorkspaceId == nil || *a.WorkspaceId != filter.WorkspaceID {
46→				continue
47→			}
48→		}
49→		if filter.Status != nil && a.Status != *filter.Status {
50→			continue
51→		}
52→		if filter.IntentID != "" && a.IntentId != filter.IntentID {
53→			continue
54→		}
55→		result = append(result, a)
56→	}
57→	return result, nil
58→}
59→
60→func (s *ApprovalStore) Update(_ context.Context, approval api.Approval) error {
61→	s.mu.Lock()
62→	defer s.mu.Unlock()
63→	if _, ok := s.approvals[approval.ApprovalId]; !ok {
64→		return &store.ErrNotFound{Entity: "approval", ID: approval.ApprovalId}
65→	}
66→	s.approvals[approval.ApprovalId] = approval
67→	return nil
68→}
