 87→	now := time.Now().UTC()
 88→	a.ResolvedAt = &now
 89→	if err := s.Update(ctx, a); err != nil {
 90→		t.Fatalf("Update: %v", err)
 91→	}
 92→
 93→	got, _ := s.Get(ctx, "apr_1")
 94→	if got.Status != api.ApprovalStatusApproved {
 95→		t.Errorf("Status = %q, want %q", got.Status, api.ApprovalStatusApproved)
 96→	}
 97→	if got.ResolvedAt == nil {
 98→		t.Error("ResolvedAt should be set")
 99→	}
100→}
