 14→// ---------------------------------------------------------------------------
 15→// Mock MCP server helper process
 16→//
 17→// When the test binary is re-invoked with MCPCLIENT_TEST_HELPER=1, it acts
 18→// as a minimal MCP server that reads newline-delimited JSON-RPC from stdin
 19→// and writes responses to stdout. This follows the pattern used by the
 20→// standard library's os/exec tests.
 21→// ---------------------------------------------------------------------------
 22→
 23→func TestHelperProcess(t *testing.T) {
 24→	if os.Getenv("MCPCLIENT_TEST_HELPER") != "1" {
 25→		return
 26→	}
 27→
 28→	// We're acting as a mock MCP server. Read requests from stdin, write
 29→	// responses to stdout. Exit cleanly on EOF.
 30→	scanner := bufio.NewScanner(os.Stdin)
 31→	for scanner.Scan() {
 32→		line := scanner.Bytes()
 33→		var req jsonrpcRequest
 34→		if err := json.Unmarshal(line, &req); err != nil {
 35→			fmt.Fprintf(os.Stderr, "mock server: bad request: %s\n", err)
 36→			continue
 37→		}
 38→
 39→		resp := handleMockRequest(req)
 40→		if resp == nil {
 41→			// Notification — no response.
 42→			continue
 43→		}
 44→
 45→		data, _ := json.Marshal(resp)
 46→		fmt.Fprintf(os.Stdout, "%s\n", data)
 47→	}
 48→	os.Exit(0)
 49→}
 50→
 51→func handleMockRequest(req jsonrpcRequest) *jsonrpcResponse {
 52→	// Notifications have no ID and expect no response.
 53→	if req.ID == nil {
 54→		return nil
 55→	}
 56→
 57→	idRaw, _ := json.Marshal(req.ID)
 58→
 59→	switch req.Method {
 60→	case "initialize":
 61→		result, _ := json.Marshal(map[string]any{
 62→			"protocolVersion": "2024-11-05",
 63→			"capabilities":    map[string]any{},
 64→			"serverInfo": map[string]any{
 65→				"name":    "mock-mcp-server",
 66→				"version": "0.0.1",
 67→			},
 68→		})
 69→		return &jsonrpcResponse{
 70→			JSONRPC: "2.0",
 71→			ID:      idRaw,
 72→			Result:  result,
 73→		}
 74→
 75→	case "tools/list":
 76→		result, _ := json.Marshal(map[string]any{
 77→			"tools": []ToolDef{
 78→				{
 79→					Name:        "echo",
 80→					Description: "Echoes the input back",
 81→					InputSchema: map[string]any{
 82→						"type": "object",
 83→						"properties": map[string]any{
 84→							"message": map[string]any{"type": "string"},
 85→						},
 86→					},
 87→				},
 88→				{
 89→					Name:        "greet",
 90→					Description: "Returns a greeting",
 91→					InputSchema: map[string]any{
 92→						"type": "object",
 93→						"properties": map[string]any{
 94→							"name": map[string]any{"type": "string"},
 95→						},
 96→					},
 97→				},
 98→			},
 99→		})
100→		return &jsonrpcResponse{
101→			JSONRPC: "2.0",
102→			ID:      idRaw,
103→			Result:  result,
104→		}
105→
106→	case "tools/call":
107→		paramsRaw, _ := json.Marshal(req.Params)
108→		var params struct {
109→			Name      string         `json:"name"`
110→			Arguments map[string]any `json:"arguments"`
111→		}
112→		_ = json.Unmarshal(paramsRaw, &params)
113→
114→		switch params.Name {
115→		case "echo":
116→			msg, _ := params.Arguments["message"].(string)
117→			result, _ := json.Marshal(ToolResult{
118→				Content: []ToolContent{{Type: "text", Text: msg}},
119→			})
120→			return &jsonrpcResponse{
121→				JSONRPC: "2.0",
122→				ID:      idRaw,
123→				Result:  result,
124→			}
125→		case "greet":
126→			name, _ := params.Arguments["name"].(string)
127→			result, _ := json.Marshal(ToolResult{
128→				Content: []ToolContent{{Type: "text", Text: "Hello, " + name + "!"}},
129→			})
130→			return &jsonrpcResponse{
131→				JSONRPC: "2.0",
132→				ID:      idRaw,
133→				Result:  result,
134→			}
135→		case "fail":
136→			result, _ := json.Marshal(ToolResult{
137→				Content: []ToolContent{{Type: "text", Text: "something went wrong"}},
138→				IsError: true,
139→			})
140→			return &jsonrpcResponse{
141→				JSONRPC: "2.0",
142→				ID:      idRaw,
143→				Result:  result,
144→			}
145→		default:
146→			return &jsonrpcResponse{
147→				JSONRPC: "2.0",
148→				ID:      idRaw,
149→				Error:   &jsonrpcError{Code: -32601, Message: "unknown tool: " + params.Name},
150→			}
151→		}
152→
153→	default:
154→		return &jsonrpcResponse{
155→			JSONRPC: "2.0",
156→			ID:      idRaw,
157→			Error:   &jsonrpcError{Code: -32601, Message: "method not found"},
158→		}
159→	}
160→}
