package mcpclient

import (
	"bufio"
	"context"
	"encoding/json"
	"fmt"
	"os"
	"syscall"
	"testing"
	"time"
)

// ---------------------------------------------------------------------------
// Mock MCP server helper process
//
// When the test binary is re-invoked with MCPCLIENT_TEST_HELPER=1, it acts
// as a minimal MCP server that reads newline-delimited JSON-RPC from stdin
// and writes responses to stdout. This follows the pattern used by the
// standard library's os/exec tests.
// ---------------------------------------------------------------------------

func TestHelperProcess(t *testing.T) {
	if os.Getenv("MCPCLIENT_TEST_HELPER") != "1" {
		return
	}

	// We're acting as a mock MCP server. Read requests from stdin, write
	// responses to stdout. Exit cleanly on EOF.
	scanner := bufio.NewScanner(os.Stdin)
	for scanner.Scan() {
		line := scanner.Bytes()
		var req jsonrpcRequest
		if err := json.Unmarshal(line, &req); err != nil {
			fmt.Fprintf(os.Stderr, "mock server: bad request: %s\n", err)
			continue
		}

		resp := handleMockRequest(req)
		if resp == nil {
			// Notification — no response.
			continue
		}

		data, _ := json.Marshal(resp)
		fmt.Fprintf(os.Stdout, "%s\n", data)
	}
	os.Exit(0)
}

func handleMockRequest(req jsonrpcRequest) *jsonrpcResponse {
	// Notifications have no ID and expect no response.
	if req.ID == nil {
		return nil
	}

	idRaw, _ := json.Marshal(req.ID)

	switch req.Method {
	case "initialize":
		result, _ := json.Marshal(map[string]any{
			"protocolVersion": "2024-11-05",
			"capabilities":    map[string]any{},
			"serverInfo": map[string]any{
				"name":    "mock-mcp-server",
				"version": "0.0.1",
			},
		})
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      idRaw,
			Result:  result,
		}

	case "tools/list":
		result, _ := json.Marshal(map[string]any{
			"tools": []ToolDef{
				{
					Name:        "echo",
					Description: "Echoes the input back",
					InputSchema: map[string]any{
						"type": "object",
						"properties": map[string]any{
							"message": map[string]any{"type": "string"},
						},
					},
				},
				{
					Name:        "greet",
					Description: "Returns a greeting",
					InputSchema: map[string]any{
						"type": "object",
						"properties": map[string]any{
							"name": map[string]any{"type": "string"},
						},
					},
				},
			},
		})
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      idRaw,
			Result:  result,
		}

	case "tools/call":
		paramsRaw, _ := json.Marshal(req.Params)
		var params struct {
			Name      string         `json:"name"`
			Arguments map[string]any `json:"arguments"`
		}
		_ = json.Unmarshal(paramsRaw, &params)

		switch params.Name {
		case "echo":
			msg, _ := params.Arguments["message"].(string)
			result, _ := json.Marshal(ToolResult{
				Content: []ToolContent{{Type: "text", Text: msg}},
			})
			return &jsonrpcResponse{
				JSONRPC: "2.0",
				ID:      idRaw,
				Result:  result,
			}
		case "greet":
			name, _ := params.Arguments["name"].(string)
			result, _ := json.Marshal(ToolResult{
				Content: []ToolContent{{Type: "text", Text: "Hello, " + name + "!"}},
			})
			return &jsonrpcResponse{
				JSONRPC: "2.0",
				ID:      idRaw,
				Result:  result,
			}
		case "fail":
			result, _ := json.Marshal(ToolResult{
				Content: []ToolContent{{Type: "text", Text: "something went wrong"}},
				IsError: true,
			})
			return &jsonrpcResponse{
				JSONRPC: "2.0",
				ID:      idRaw,
				Result:  result,
			}
		default:
			return &jsonrpcResponse{
				JSONRPC: "2.0",
				ID:      idRaw,
				Error:   &jsonrpcError{Code: -32601, Message: "unknown tool: " + params.Name},
			}
		}

	default:
		return &jsonrpcResponse{
			JSONRPC: "2.0",
			ID:      idRaw,
			Error:   &jsonrpcError{Code: -32601, Message: "method not found"},
		}
	}
}

