	t.Setenv("AILERON_CONFIG", "")

	cfg, err := LoadFromEnvOrDefault()
	if err != nil {
		t.Fatalf("LoadFromEnvOrDefault() unexpected error: %v", err)
	}
	if cfg == nil {
		t.Fatal("LoadFromEnvOrDefault() returned nil config, want non-nil empty config")
