	}

	route, ok := g.routes[call.QualifiedName]
	if !ok {
		return errorResult("downstream server no longer available for tool: " + call.QualifiedName)
	}

	g.log.Info("auto-executing approved tool call",
		"tool", call.QualifiedName,
