378→	}
379→
380→	// ToolCall context should be populated.
381→	if capturedReq.ToolCall == nil {
382→		t.Fatal("expected ToolCall context")
383→	}
384→	if capturedReq.ToolCall.ServerName != "github" {
385→		t.Errorf("ToolCall.ServerName = %q, want %q", capturedReq.ToolCall.ServerName, "github")
386→	}
387→	if capturedReq.ToolCall.Arguments["base"] != "main" {
388→		t.Errorf("ToolCall.Arguments[base] = %v, want %q", capturedReq.ToolCall.Arguments["base"], "main")
389→	}
