392→// capturingPolicyEngine records the last evaluation request.
393→type capturingPolicyEngine struct {
394→	decision model.Decision
395→	captured *policy.EvaluationRequest
396→}
397→
398→func (c *capturingPolicyEngine) Evaluate(_ context.Context, req policy.EvaluationRequest) (model.Decision, error) {
399→	*c.captured = req
400→	return c.decision, nil
401→}
